//! Head-to-head benchmark: Percolator vs mokaccino
//!
//! Measures both engines on identical normalized data generated by Percolator's
//! synthetic data generator. The bridge translates our semantic features into
//! mokaccino's (field, value) Document/Query model.
//!
//! Usage: mokabench [num_queries] [num_titles] [broad_frac] [skew] [seed]

use mokaccino::prelude::*;
use percolator::compile::extract;
use percolator::dict::Dict;
use percolator::dsl;
use percolator::gen::{generate, GenConfig};
use percolator::normalize::Normalizer;
use percolator::segment::{Engine, MatchScratch};
use std::num::NonZeroUsize;
use std::time::Instant;

// ─── Translation bridge ─────────────────────────────────────────────────────

/// Split a Percolator feature name like "player:michael_jordan" into a
/// mokaccino (field, value) pair. Features without `:` get field "term".
fn feature_to_field_value(name: &str) -> (&str, &str) {
    if let Some(idx) = name.find(':') {
        (&name[..idx], &name[idx + 1..])
    } else {
        ("term", name)
    }
}

/// Translate a Percolator query (DSL text) into a mokaccino Query using the
/// same normalizer. Returns None if the query can't be translated (class D).
fn translate_query(
    query_text: &str,
    norm: &Normalizer,
    dict: &mut Dict,
    lc: &mut String,
) -> Option<Query> {
    let ast = dsl::parse(query_text).ok()?;
    let ex = extract(&ast, norm, dict, lc);

    // Class D = no required and no any-of → can't be indexed meaningfully
    if ex.required.is_empty() && ex.anyof.is_empty() {
        return None;
    }

    // Build the mokaccino query from extracted features:
    //   required features → AND of has_value clauses
    //   any-of groups → OR clauses
    //   forbidden features → negated has_value clauses
    let mut parts: Vec<Query> = Vec::new();

    for &fid in &ex.required {
        let name = dict.name(fid);
        let (field, value) = feature_to_field_value(name);
        parts.push(field.has_value(value));
    }

    for group in &ex.anyof {
        if group.len() == 1 {
            let name = dict.name(group[0]);
            let (field, value) = feature_to_field_value(name);
            parts.push(field.has_value(value));
        } else {
            // OR group
            let mut or_q: Option<Query> = None;
            for &fid in group {
                let name = dict.name(fid);
                let (field, value) = feature_to_field_value(name);
                let clause = field.has_value(value);
                or_q = Some(match or_q {
                    None => clause,
                    Some(prev) => prev | clause,
                });
            }
            if let Some(q) = or_q {
                parts.push(q);
            }
        }
    }

    for &fid in &ex.forbidden {
        let name = dict.name(fid);
        let (field, value) = feature_to_field_value(name);
        parts.push(!field.has_value(value));
    }

    // AND all parts together
    let mut combined: Option<Query> = None;
    for p in parts {
        combined = Some(match combined {
            None => p,
            Some(prev) => prev & p,
        });
    }

    combined
}

/// Translate a title (raw text) into a mokaccino Document by normalizing it
/// through our normalizer and converting each feature to a (field, value) pair.
fn translate_title(title: &str, norm: &Normalizer, dict: &Dict) -> Vec<(&'static str, String)> {
    let mut lc = String::new();
    let mut features: Vec<percolator::FeatureId> = Vec::new();
    norm.match_features(title, dict, &mut lc, &mut features);
    let mut pairs: Vec<(&'static str, String)> = Vec::new();

    for fid in &features {
        let name = dict.name(*fid);
        let (field, value) = feature_to_field_value(name);
        // Leak the strings into static since mokaccino Document wants &str
        // (benchmark only — not production code)
        pairs.push((leak_str(field), value.to_string()));
    }
    pairs
}

/// Leak a string to get a &'static str. Fine for benchmarks (fixed vocabulary).
fn leak_str(s: &str) -> &'static str {
    // Cache leaked strings to avoid unbounded leaking
    use std::collections::HashMap;
    use std::sync::Mutex;
    static CACHE: std::sync::LazyLock<Mutex<HashMap<String, &'static str>>> =
        std::sync::LazyLock::new(|| Mutex::new(HashMap::new()));

    let mut cache = CACHE.lock().unwrap();
    if let Some(&leaked) = cache.get(s) {
        return leaked;
    }
    let leaked: &'static str = Box::leak(s.to_string().into_boxed_str());
    cache.insert(s.to_string(), leaked);
    leaked
}

/// Build a mokaccino Document from a dynamic list of (field, value) pairs.
fn build_document(pairs: &[(&str, &str)]) -> Document {
    let mut doc = Document::new();
    for &(field, value) in pairs {
        doc.with_value_mut(field, value);
    }
    doc
}

// ─── Main benchmark ─────────────────────────────────────────────────────────

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let num_queries = arg_usize(&args, 1, 100_000);
    let num_titles = arg_usize(&args, 2, 10_000);
    let broad_frac = arg_f64(&args, 3, 0.05);
    let skew = arg_f64(&args, 4, 2.0);
    let seed = arg_u64(&args, 5, 0xC0FFEE);

    let cfg = GenConfig {
        num_queries,
        num_titles,
        broad_query_frac: broad_frac,
        hot_skew: skew,
        family_size: 8,
        seed,
        num_players: (num_queries / 40).max(2_000),
        num_sets: (num_queries / 100).max(1_000),
    };

    eprintln!(
        "╔══════════════════════════════════════════════════════════════╗"
    );
    eprintln!(
        "║  Percolator vs mokaccino — head-to-head benchmark          ║"
    );
    eprintln!(
        "╠══════════════════════════════════════════════════════════════╣"
    );
    eprintln!(
        "║  queries={:<8} titles={:<8} broad={:.0}% skew={:.1}       ║",
        num_queries, num_titles, broad_frac * 100.0, skew
    );
    eprintln!(
        "╚══════════════════════════════════════════════════════════════╝"
    );

    // ── Generate data ──
    eprintln!("\n[1/5] Generating synthetic data...");
    let t0 = Instant::now();
    let data = generate(&cfg);
    eprintln!("      done in {:.2}s", t0.elapsed().as_secs_f64());

    // ══════════════════════════════════════════════════════════════════════════
    // PERCOLATOR
    // ══════════════════════════════════════════════════════════════════════════
    eprintln!("\n[2/5] Building Percolator engine...");
    let norm = Normalizer::default_vocab().expect("built-in vocab");
    let mut eng = Engine::new(norm);
    let tb = Instant::now();
    eng.build_from_queries(&data.queries);
    let perc_build_s = tb.elapsed().as_secs_f64();
    let perc_num_indexed = eng.num_queries();
    let cc = eng.class_counts();

    eprintln!(
        "      indexed: {} (A={} B={} C={} D={})",
        perc_num_indexed, cc[0], cc[1], cc[2], cc[3]
    );
    eprintln!(
        "      build: {:.2}s ({:.0} queries/sec)",
        perc_build_s,
        perc_num_indexed as f64 / perc_build_s
    );

    // Match throughput
    let mut scratch = MatchScratch::new();
    let mut out: Vec<u64> = Vec::new();

    // warmup
    for t in data.titles.iter().take(500) {
        eng.match_title(t, &mut scratch, &mut out, true);
    }

    let reps = (200_000 / num_titles.max(1)).max(3);
    let tm = Instant::now();
    let mut perc_total_matches: u64 = 0;
    for _ in 0..reps {
        for t in &data.titles {
            let st = eng.match_title(t, &mut scratch, &mut out, true);
            perc_total_matches += st.matches as u64;
        }
    }
    let perc_match_s = tm.elapsed().as_secs_f64();
    let perc_total_titles = reps * data.titles.len();
    let perc_tps = perc_total_titles as f64 / perc_match_s;

    // Per-title stats (single pass)
    let mut perc_cands: Vec<u32> = Vec::with_capacity(data.titles.len());
    let mut perc_lat_ns: Vec<u64> = Vec::with_capacity(data.titles.len());
    let mut perc_matches_per_title: Vec<u32> = Vec::with_capacity(data.titles.len());
    for t in &data.titles {
        let s0 = Instant::now();
        let st = eng.match_title(t, &mut scratch, &mut out, true);
        perc_lat_ns.push(s0.elapsed().as_nanos() as u64);
        perc_cands.push(st.unique_candidates);
        perc_matches_per_title.push(st.matches);
    }

    let perc_rss = read_rss_mb();

    // ══════════════════════════════════════════════════════════════════════════
    // MOKACCINO — translate and build
    // ══════════════════════════════════════════════════════════════════════════
    eprintln!("\n[3/5] Building mokaccino engine (translating queries)...");

    // We need a separate dict for the bridge (since Dict is mutated during extract).
    // Use the same normalizer to ensure identical feature spaces.
    let norm3 = Normalizer::default_vocab().expect("built-in vocab");
    let mut dict3 = Dict::new();
    let mut lc3 = String::new();

    // First pass: extract all queries to populate dict3 (need frequencies for title lookup)
    let mut extracted_queries: Vec<(u64, Option<Query>)> = Vec::with_capacity(data.queries.len());
    for (logical_id, query_text) in &data.queries {
        let moka_q = translate_query(query_text, &norm3, &mut dict3, &mut lc3);
        extracted_queries.push((*logical_id, moka_q));
    }

    // Finalize the dict so title_features works
    dict3.finalize_mask();

    // Sweep n_clause_matchers
    for n_cm in [2usize, 3, 4] {
        eprintln!("\n      --- mokaccino with n_clause_matchers={} ---", n_cm);

        let tb_m = Instant::now();
        let mut moka = Percolator::builder()
            .n_clause_matchers(NonZeroUsize::new(n_cm).unwrap())
            .build();

        let mut moka_indexed = 0u64;
        let mut moka_rejected = 0u64;
        for (_logical_id, moka_q) in &extracted_queries {
            if let Some(q) = moka_q.clone() {
                moka.add_query(q);
                moka_indexed += 1;
            } else {
                moka_rejected += 1;
            }
        }
        let moka_build_s = tb_m.elapsed().as_secs_f64();
        eprintln!(
            "      indexed: {} (rejected: {})",
            moka_indexed, moka_rejected
        );
        eprintln!(
            "      build: {:.2}s ({:.0} queries/sec)",
            moka_build_s,
            moka_indexed as f64 / moka_build_s
        );

        // Translate titles into mokaccino Documents
        // Pre-build all documents for fair timing
        let docs: Vec<Vec<(& 'static str, String)>> = data
            .titles
            .iter()
            .map(|t| translate_title(t, &norm3, &dict3))
            .collect();

        // Warmup
        for doc_pairs in docs.iter().take(500) {
            let doc_refs: Vec<(&str, &str)> =
                doc_pairs.iter().map(|(f, v)| (*f, v.as_str())).collect();
            let _: Vec<_> = moka.percolate(&build_document(&doc_refs)).collect();
        }

        // Throughput pass
        let tm_m = Instant::now();
        let mut moka_total_matches: u64 = 0;
        for _ in 0..reps {
            for doc_pairs in &docs {
                let doc_refs: Vec<(&str, &str)> =
                    doc_pairs.iter().map(|(f, v)| (*f, v.as_str())).collect();
                let matches: Vec<_> = moka.percolate(&build_document(&doc_refs)).collect();
                moka_total_matches += matches.len() as u64;
            }
        }
        let moka_match_s = tm_m.elapsed().as_secs_f64();
        let moka_tps = perc_total_titles as f64 / moka_match_s;

        // Per-title stats
        let mut moka_matches_per: Vec<u32> = Vec::with_capacity(data.titles.len());
        let mut moka_lat_ns: Vec<u64> = Vec::with_capacity(data.titles.len());
        for doc_pairs in &docs {
            let doc_refs: Vec<(&str, &str)> =
                doc_pairs.iter().map(|(f, v)| (*f, v.as_str())).collect();
            let s0 = Instant::now();
            let matches: Vec<_> = moka.percolate(&build_document(&doc_refs)).collect();
            moka_lat_ns.push(s0.elapsed().as_nanos() as u64);
            moka_matches_per.push(matches.len() as u32);
        }

        let moka_rss = read_rss_mb();

        // ── Print comparison table ──
        if n_cm == 3 {
            // Primary comparison (default config)
            println!("\n╔══════════════════════════════════════════════════════════════════════╗");
            println!("║         HEAD-TO-HEAD RESULTS (n_clause_matchers={})               ║", n_cm);
            println!("╠══════════════════════════════════════════════════════════════════════╣");
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Metric", "Percolator", "mokaccino"
            );
            println!("╠══════════════════════════════════════════════════════════════════════╣");
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Queries indexed",
                format!("{}", perc_num_indexed),
                format!("{}", moka_indexed)
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Build (queries/sec)",
                format!("{:.0}", perc_num_indexed as f64 / perc_build_s),
                format!("{:.0}", moka_indexed as f64 / moka_build_s)
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Match (titles/sec/core)",
                format!("{:.0}", perc_tps),
                format!("{:.0}", moka_tps)
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Speedup vs mokaccino",
                format!("{:.1}x", perc_tps / moka_tps),
                "1.0x"
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Total matches (verify)",
                format!("{}", perc_total_matches / reps as u64),
                format!("{}", moka_total_matches / reps as u64)
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Avg matches/title",
                format!(
                    "{:.2}",
                    perc_matches_per_title.iter().map(|x| *x as f64).sum::<f64>()
                        / data.titles.len() as f64
                ),
                format!(
                    "{:.2}",
                    moka_matches_per.iter().map(|x| *x as f64).sum::<f64>()
                        / data.titles.len() as f64
                )
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Avg candidates/title",
                format!(
                    "{:.1}",
                    perc_cands.iter().map(|x| *x as f64).sum::<f64>() / data.titles.len() as f64
                ),
                "(N/A)"
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Latency p50",
                format!("{}ns", pct_u64(&mut perc_lat_ns.clone(), 0.50)),
                format!("{}ns", pct_u64(&mut moka_lat_ns.clone(), 0.50))
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Latency p95",
                format!("{}ns", pct_u64(&mut perc_lat_ns.clone(), 0.95)),
                format!("{}ns", pct_u64(&mut moka_lat_ns.clone(), 0.95))
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "Latency p99",
                format!("{}ns", pct_u64(&mut perc_lat_ns.clone(), 0.99)),
                format!("{}ns", pct_u64(&mut moka_lat_ns.clone(), 0.99))
            );
            println!(
                "║  {:30} {:>14} {:>14}  ║",
                "RSS (MB)",
                format!("{:.1}", perc_rss),
                format!("{:.1}", moka_rss)
            );
            println!("╚══════════════════════════════════════════════════════════════════════╝");
        } else {
            println!(
                "\n  n_clause_matchers={}: {:.0} titles/sec  ({:.1}x vs Percolator)  matches/title={:.2}  p50={}ns  p99={}ns",
                n_cm,
                moka_tps,
                moka_tps / perc_tps,
                moka_matches_per.iter().map(|x| *x as f64).sum::<f64>() / data.titles.len() as f64,
                pct_u64(&mut moka_lat_ns.clone(), 0.50),
                pct_u64(&mut moka_lat_ns.clone(), 0.99),
            );
        }
    }

    // ── Correctness check ──
    eprintln!("\n[4/5] Differential correctness check (first 1000 titles)...");
    // Compare match COUNTS between both engines. Exact set comparison is hard
    // because query IDs differ and mokaccino doesn't index class-D/C queries
    // the same way. Instead verify that matches are in the same ballpark and
    // both find >0 matches for the same titles.
    let norm4 = Normalizer::default_vocab().expect("built-in vocab");
    let mut dict4 = Dict::new();
    let mut lc4 = String::new();

    // Rebuild a mokaccino with default config that uses our query IDs
    let mut moka_check = PercolatorUid::<u64>::default();

    let mut indexed_ids: Vec<u64> = Vec::new();
    for (logical_id, query_text) in &data.queries {
        let moka_q = translate_query(query_text, &norm4, &mut dict4, &mut lc4);
        if let Some(q) = moka_q {
            let _ = moka_check.index_query_uid(q, *logical_id);
            indexed_ids.push(*logical_id);
        }
    }
    dict4.finalize_mask();

    let check_n = 1000.min(data.titles.len());
    let mut agree = 0u64;
    let mut disagree = 0u64;
    let mut perc_extra = 0u64;
    let mut moka_extra = 0u64;

    for t in data.titles.iter().take(check_n) {
        // Percolator matches
        let _st = eng.match_title(t, &mut scratch, &mut out, true);
        let perc_set: std::collections::HashSet<u64> = out.iter().copied().collect();

        // mokaccino matches
        let title_feats = translate_title(t, &norm4, &dict4);
        let doc_refs: Vec<(&str, &str)> = title_feats.iter().map(|(f, v)| (*f, v.as_str())).collect();
        let moka_matches: Vec<u64> = moka_check.percolate(&build_document(&doc_refs)).collect();
        let moka_set: std::collections::HashSet<u64> = moka_matches.into_iter().collect();

        // Compare (only queries indexed in mokaccino)
        let indexed_set: std::collections::HashSet<u64> = indexed_ids.iter().copied().collect();
        let perc_comparable: std::collections::HashSet<u64> =
            perc_set.intersection(&indexed_set).copied().collect();

        if perc_comparable == moka_set {
            agree += 1;
        } else {
            disagree += 1;
            perc_extra += perc_comparable.difference(&moka_set).count() as u64;
            moka_extra += moka_set.difference(&perc_comparable).count() as u64;
        }
    }

    println!("\n══ CORRECTNESS CHECK ({} titles) ══", check_n);
    println!("  Titles with identical matches: {} ({:.1}%)", agree, agree as f64 / check_n as f64 * 100.0);
    println!("  Titles with differences: {}", disagree);
    if disagree > 0 {
        println!("    Percolator-only matches: {} (false positives or translation gap)", perc_extra);
        println!("    mokaccino-only matches: {} (translation gap or mokaccino false positives)", moka_extra);
    }

    eprintln!("\n[5/5] Done.");
}

// ─── Utility ────────────────────────────────────────────────────────────────

fn pct_u64(v: &mut [u64], q: f64) -> u64 {
    if v.is_empty() {
        return 0;
    }
    v.sort_unstable();
    let idx = ((v.len() as f64 - 1.0) * q).round() as usize;
    v[idx]
}

fn read_rss_mb() -> f64 {
    // Linux: /proc/self/status
    if let Ok(s) = std::fs::read_to_string("/proc/self/status") {
        for line in s.lines() {
            if let Some(rest) = line.strip_prefix("VmRSS:") {
                let kb: f64 = rest
                    .split_whitespace()
                    .next()
                    .and_then(|x| x.parse().ok())
                    .unwrap_or(0.0);
                return kb / 1024.0;
            }
        }
    }
    // macOS: use ps
    if let Ok(output) = std::process::Command::new("ps")
        .args(["-o", "rss=", "-p", &std::process::id().to_string()])
        .output()
    {
        if let Ok(s) = String::from_utf8(output.stdout) {
            if let Ok(kb) = s.trim().parse::<f64>() {
                return kb / 1024.0;
            }
        }
    }
    0.0
}

fn arg_usize(a: &[String], i: usize, d: usize) -> usize {
    a.get(i).and_then(|x| x.parse().ok()).unwrap_or(d)
}
fn arg_f64(a: &[String], i: usize, d: f64) -> f64 {
    a.get(i).and_then(|x| x.parse().ok()).unwrap_or(d)
}
fn arg_u64(a: &[String], i: usize, d: u64) -> u64 {
    a.get(i).and_then(|x| x.parse().ok()).unwrap_or(d)
}
